import type TurndownService from "./turndown";

const highlightRegExp = /highlight-(?:text|source)-([a-z0-9]+)/;

function highlightedCodeBlock(turndownService: TurndownService): void {
    turndownService.addRule("highlightedCodeBlock", {
        filter(node: HTMLElement) {
            const firstChild = node.firstChild;
            return (
                node.nodeName === "DIV" &&
                highlightRegExp.test(node.className) &&
                firstChild !== null &&
                firstChild.nodeName === "PRE"
            );
        },
        replacement(content: string, node: Node, options: TurndownService.Options) {
            // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
            const className = (node as HTMLElement).className ?? "";
            const language = (className.match(highlightRegExp) ?? [null, ""])[1];

            return `\n\n${options.fence}${language}\n${
                (node.firstChild as HTMLElement).textContent
            }\n${options.fence}\n\n`;
        },
    });
}

function strikethrough(turndownService: TurndownService): void {
    turndownService.addRule("strikethrough", {
        filter: ["del", "s", "strike" as any],
        replacement(content: string, node: Node, options: any) {
            return `~${content}~`;
        },
    });
}

// Unfortunate turndown hack to get indexOf and every to work with NodeList
// eslint-disable-next-line @typescript-eslint/unbound-method
const indexOf = Array.prototype.indexOf;
// eslint-disable-next-line @typescript-eslint/unbound-method
const every = Array.prototype.every;

const tableRules: { [key: string]: TurndownService.Rule } = {
    tableCell: {
        filter: ["th", "td"],
        replacement(content: string, node: Node) {
            return cell(content, node);
        },
    },

    tableRow: {
        filter: "tr",
        replacement(content: string, node: Node) {
            let borderCells = "";
            const alignMap: { [key: string]: string } = {
                left: ":--",
                right: "--:",
                center: ":-:",
            };

            if (isHeadingRow(node)) {
                node.childNodes.forEach(n => {
                    let border = "---";
                    const align = ((n as HTMLElement).getAttribute("align") ?? "").toLowerCase();

                    if (align) {
                        border = alignMap[align] || border;
                    }

                    borderCells += cell(border, n as HTMLElement);
                });
            }
            return `\n${content}${borderCells ? `\n${borderCells}` : ""}`;
        },
    },

    table: {
        filter(node: Node) {
            return node.nodeName === "TABLE";
        },
        replacement(content: string, node: Node) {
            const firstRow = (node as HTMLTableElement).rows.item(0);
            if (!firstRow) {
                return "";
            }
            content = content.replace("\n\n", "\n");
            if (!isHeadingRow(firstRow)) {
                let cells = "";
                firstRow.childNodes.forEach(node => (cells += cell(" ", node)));
                cells += "\n";
                firstRow.childNodes.forEach(node => (cells += cell("---", node)));
                cells += "\n";
                content = cells + content.trim();
            }
            return `\n\n${content}\n\n`;
        },
    },

    tableSection: {
        filter: ["thead", "tbody", "tfoot"],
        replacement(content: string) {
            return content;
        },
    },
};

function isHeadingRow(tr: Node): boolean {
    const parentNode = tr.parentNode as HTMLElement;
    return (
        parentNode.nodeName === "THEAD" ||
        (parentNode.firstChild === tr &&
            (parentNode.nodeName === "TABLE" || isFirstTbody(parentNode)) &&
            every.call(tr.childNodes, function (n: ChildNode) {
                return n.nodeName === "TH";
            }))
    );
}

function isFirstTbody(element: HTMLElement): boolean {
    const previousSibling = element.previousSibling as HTMLElement | null;
    return (
        element.nodeName === "TBODY" &&
        (previousSibling === null ||
            (previousSibling.nodeName === "THEAD" &&
                /^\s*$/i.test(previousSibling.textContent ?? "")))
    );
}

function cell(content: string, node: Node): string {
    const index = indexOf.call(node.parentNode!.childNodes, node);
    let prefix = " ";
    if (index === 0) {
        prefix = "| ";
    }
    return `${prefix + content.trim()} |`;
}

function tables(turndownService: TurndownService): void {
    for (const key in tableRules) {
        turndownService.addRule(key, tableRules[key]);
    }
}

function taskListItems(turndownService: TurndownService): void {
    turndownService.addRule("taskListItems", {
        filter(node: Node) {
            return (
                (node as HTMLInputElement).type === "checkbox" && node.parentNode!.nodeName === "LI"
            );
        },
        replacement(content: string, node: Node) {
            return `${(node as HTMLInputElement).checked ? "[x]" : "[ ]"} `;
        },
    });
}

function gfm(turndownService: TurndownService): void {
    turndownService.use([highlightedCodeBlock, strikethrough, tables, taskListItems]);
}

function stripImages(turndownService: TurndownService): void {
    turndownService.addRule("stripImages", {
        filter: "img",
        replacement() {
            return "";
        },
    });
}

export { gfm, highlightedCodeBlock, strikethrough, tables, taskListItems, stripImages };
