//
// Injected into every esbuild lazy-module bundle so transitive deps (e.g.
// entities@7.0.1 via sanitize-html) can decode base64 without Node Buffer.
// goja has no atob/Buffer; we inject at build time rather than defining
// globals once in gojax so each self-contained IIFE matches how the runtime
// loads bundles and TestLazyArtifactsLoadInRuntime exercises the shipped artifact.

const base64Chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

if (typeof globalThis.atob === "undefined") {
    globalThis.atob = function atob(input) {
        const str = String(input).replace(/[\t\n\f\r ]+/g, "");
        if (str.length % 4 === 1) {
            throw new Error("InvalidCharacterError");
        }

        let output = "";
        let buffer = 0;
        let bits = 0;

        for (let i = 0; i < str.length; i++) {
            const char = str.charAt(i);
            if (char === "=") {
                break;
            }

            const index = base64Chars.indexOf(char);
            if (index < 0) {
                throw new Error("InvalidCharacterError");
            }

            buffer = (buffer << 6) | index;
            bits += 6;

            if (bits >= 8) {
                bits -= 8;
                output += String.fromCharCode((buffer >> bits) & 0xff);
            }
        }

        return output;
    };
}

if (typeof globalThis.btoa === "undefined") {
    globalThis.btoa = function btoa(input) {
        const str = String(input);
        let output = "";

        for (let i = 0; i < str.length; i += 3) {
            const byte1 = str.charCodeAt(i);
            const byte2 = str.charCodeAt(i + 1);
            const byte3 = str.charCodeAt(i + 2);
            const triplet = (byte1 << 16) | ((byte2 || 0) << 8) | (byte3 || 0);

            output += base64Chars[(triplet >> 18) & 63];
            output += base64Chars[(triplet >> 12) & 63];
            output += i + 1 < str.length ? base64Chars[(triplet >> 6) & 63] : "=";
            output += i + 2 < str.length ? base64Chars[triplet & 63] : "=";
        }

        return output;
    };
}
